// lib/models/auth_tokens.dart
import 'dart:convert';

class AuthTokens {
  final String accessToken;
  final String refreshToken;
  final DateTime expiresAt;

  const AuthTokens({
    required this.accessToken,
    required this.refreshToken,
    required this.expiresAt,
  });

  bool get isExpired => DateTime.now().isAfter(expiresAt);

  bool get isNearExpiry =>
      DateTime.now().isAfter(expiresAt.subtract(const Duration(minutes: 5)));

  Map<String, dynamic> toJson() => {
        'accessToken': accessToken,
        'refreshToken': refreshToken,
        'expiresAt': expiresAt.toIso8601String(),
      };

  factory AuthTokens.fromJson(Map<String, dynamic> json) => AuthTokens(
        accessToken: json['accessToken'] as String,
        refreshToken: json['refreshToken'] as String,
        expiresAt: DateTime.parse(json['expiresAt'] as String),
      );

  String toJsonString() => jsonEncode(toJson());

  factory AuthTokens.fromJsonString(String jsonString) =>
      AuthTokens.fromJson(jsonDecode(jsonString) as Map<String, dynamic>);
}

// lib/services/secure_storage_service.dart
import 'package:flutter_secure_storage/flutter_secure_storage.dart';

class SecureStorageService {
  static const _accessTokenKey = 'auth_access_token';
  static const _refreshTokenKey = 'auth_refresh_token';
  static const _tokenExpiryKey = 'auth_token_expiry';

  final FlutterSecureStorage _secureStorage;

  SecureStorageService({FlutterSecureStorage? secureStorage})
      : _secureStorage = secureStorage ??
            const FlutterSecureStorage(
              aOptions: AndroidOptions(encryptedSharedPreferences: true),
              iOptions: IOSOptions(
                accessibility: KeychainAccessibility.first_unlock_this_device,
              ),
            );

  Future<void> saveTokens({
    required String accessToken,
    required String refreshToken,
    required DateTime expiresAt,
  }) async {
    await Future.wait([
      _secureStorage.write(key: _accessTokenKey, value: accessToken),
      _secureStorage.write(key: _refreshTokenKey, value: refreshToken),
      _secureStorage.write(
          key: _tokenExpiryKey, value: expiresAt.toIso8601String()),
    ]);
  }

  Future<({String? accessToken, String? refreshToken, DateTime? expiresAt})>
      readTokens() async {
    final results = await Future.wait([
      _secureStorage.read(key: _accessTokenKey),
      _secureStorage.read(key: _refreshTokenKey),
      _secureStorage.read(key: _tokenExpiryKey),
    ]);

    final accessToken = results[0];
    final refreshToken = results[1];
    final expiryString = results[2];

    return (
      accessToken: accessToken,
      refreshToken: refreshToken,
      expiresAt: expiryString != null ? DateTime.tryParse(expiryString) : null,
    );
  }

  Future<void> deleteTokens() async {
    await Future.wait([
      _secureStorage.delete(key: _accessTokenKey),
      _secureStorage.delete(key: _refreshTokenKey),
      _secureStorage.delete(key: _tokenExpiryKey),
    ]);
  }

  Future<void> deleteAll() async {
    await _secureStorage.deleteAll();
  }
}

// lib/services/session_storage_service.dart
import 'package:shared_preferences/shared_preferences.dart';

/// Stores only non-sensitive session metadata in shared_preferences.
/// Sensitive tokens are stored via SecureStorageService.
class SessionStorageService {
  static const _isLoggedInKey = 'session_is_logged_in';
  static const _userIdKey = 'session_user_id';
  static const _userEmailKey = 'session_user_email';
  static const _userDisplayNameKey = 'session_user_display_name';
  static const _lastLoginKey = 'session_last_login';

  SharedPreferences? _prefs;

  Future<SharedPreferences> get _preferences async {
    _prefs ??= await SharedPreferences.getInstance();
    return _prefs!;
  }

  Future<void> saveSession({
    required String userId,
    required String email,
    required String displayName,
  }) async {
    final prefs = await _preferences;
    await Future.wait([
      prefs.setBool(_isLoggedInKey, true),
      prefs.setString(_userIdKey, userId),
      prefs.setString(_userEmailKey, email),
      prefs.setString(_userDisplayNameKey, displayName),
      prefs.setString(_lastLoginKey, DateTime.now().toIso8601String()),
    ]);
  }

  Future<bool> get isLoggedIn async {
    final prefs = await _preferences;
    return prefs.getBool(_isLoggedInKey) ?? false;
  }

  Future<({String? userId, String? email, String? displayName, DateTime? lastLogin})>
      readSession() async {
    final prefs = await _preferences;
    final lastLoginStr = prefs.getString(_lastLoginKey);
    return (
      userId: prefs.getString(_userIdKey),
      email: prefs.getString(_userEmailKey),
      displayName: prefs.getString(_userDisplayNameKey),
      lastLogin: lastLoginStr != null ? DateTime.tryParse(lastLoginStr) : null,
    );
  }

  Future<void> clearSession() async {
    final prefs = await _preferences;
    await Future.wait([
      prefs.remove(_isLoggedInKey),
      prefs.remove(_userIdKey),
      prefs.remove(_userEmailKey),
      prefs.remove(_userDisplayNameKey),
      prefs.remove(_lastLoginKey),
    ]);
  }
}

