// lib/auth/auth_manager.dart
import 'dart:async';

import '../models/auth_tokens.dart';
import '../models/user_model.dart';
import '../services/auth_api_service.dart';
import '../services/secure_storage_service.dart';
import '../services/session_storage_service.dart';
import 'auth_state.dart';

class AuthManager {
  final SecureStorageService _secureStorage;
  final SessionStorageService _sessionStorage;
  final AuthApiService _apiService;

  final StreamController<AuthState> _authStateController =
      StreamController<AuthState>.broadcast();

  AuthState _currentState = const AuthState.unknown();
  AuthTokens? _currentTokens;
  Timer? _tokenRefreshTimer;

  AuthManager({
    SecureStorageService? secureStorage,
    SessionStorageService? sessionStorage,
    AuthApiService? apiService,
  })  : _secureStorage = secureStorage ?? SecureStorageService(),
        _sessionStorage = sessionStorage ?? SessionStorageService(),
        _apiService = apiService ?? AuthApiService();

  /// Stream of auth state changes
  Stream<AuthState> get authStateChanges => _authStateController.stream;

  /// Current auth state
  AuthState get currentState => _currentState;

  /// Current access token for API calls
  String? get accessToken => _currentTokens?.accessToken;

  /// Whether user is currently authenticated
  bool get isAuthenticated => _currentState.isAuthenticated;

  /// Initialize the auth manager - call on app startup
  Future<void> initialize() async {
    _emitState(const AuthState.loading());

    try {
      final loggedIn = await _sessionStorage.isLoggedIn;
      if (!loggedIn) {
        _emitState(const AuthState.unauthenticated());
        return;
      }

      // Restore tokens from secure storage
      final storedTokens = await _secureStorage.readTokens();
      if (storedTokens.accessToken == null ||
          storedTokens.refreshToken == null ||
          storedTokens.expiresAt == null) {
        await _clearAllData();
        _emitState(const AuthState.unauthenticated());
        return;
      }

      _currentTokens = AuthTokens(
        accessToken: storedTokens.accessToken!,
        refreshToken: storedTokens.refreshToken!,
        expiresAt: storedTokens.expiresAt!,
      );

      // If token is expired, try to refresh
      if (_currentTokens!.isExpired) {
        try {
          await _refreshTokens();
        } catch (e) {
          await _clearAllData();
          _emitState(const AuthState.unauthenticated());
          return;
        }
      }

      // Restore user data from session storage
      final session = await _sessionStorage.readSession();
      if (session.userId == null || session.email == null) {
        await _clearAllData();
        _emitState(const AuthState.unauthenticated());
        return;
      }

      final user = UserModel(
        id: session.userId!,
        email: session.email!,
        displayName: session.displayName ?? session.email!,
      );

      _scheduleTokenRefresh();
      _emitState(AuthState.authenticated(user));
    } catch (e) {
      await _clearAllData();
      _emitState(const AuthState.unauthenticated());
    }
  }

  /// Login with email and password
  Future<UserModel> login({
    required String email,
    required String password,
  }) async {
    _emitState(const AuthState.loading());

    try {
      final result = await _apiService.login(
        email: email,
        password: password,
      );

      // Save tokens to secure storage
      await _secureStorage.saveTokens(
        accessToken: result.tokens.accessToken,
        refreshToken: result.tokens.refreshToken,
        expiresAt: result.tokens.expiresAt,
      );

      // Save non-sensitive session data to shared_preferences
      await _sessionStorage.saveSession(
        userId: result.user.id,
        email: result.user.email,
        displayName: result.user.displayName,
      );

      _currentTokens = result.tokens;
      _scheduleTokenRefresh();
      _emitState(AuthState.authenticated(result.user));

      return result.user;
    } on AuthApiException catch (e) {
      _emitState(AuthState.error(e.message));
      rethrow;
    } catch (e) {
      const message = 'An unexpected error occurred during login';
      _emitState(const AuthState.error(message));
      throw const AuthApiException(message);
    }
  }

  /// Logout the current user
  Future<void> logout() async {
    try {
      if (_currentTokens != null) {
        await _apiService.logout(accessToken: _currentTokens!.accessToken);
      }
    } catch (_) {
      // Best effort server-side logout; proceed with local cleanup regardless
    } finally {
      await _clearAllData();
      _emitState(const AuthState.unauthenticated());
    }
  }

  /// Force refresh the access token
  Future<void> forceRefreshToken() async {
    await _refreshTokens();
  }

  /// Get a valid access token, refreshing if necessary
  Future<String?> getValidAccessToken() async {
    if (_currentTokens == null) return null;

    if (_currentTokens!.isExpired || _currentTokens!.isNearExpiry) {
      try {
        await _refreshTokens();
      } catch (e) {
        await logout();
        return null;
      }
    }

    return _currentTokens?.accessToken;
  }

  Future<void> _refreshTokens() async {
    if (_currentTokens == null) {
      throw const AuthApiException('No refresh token available');
    }

    final newTokens = await _apiService.refreshTokens(
      refreshToken: _currentTokens!.refreshToken,
    );

    await _secureStorage.saveTokens(
      accessToken: newTokens.accessToken,
      refreshToken: newTokens.refreshToken,
      expiresAt: newTokens.expiresAt,
    );

    _currentTokens = newTokens;
    _scheduleTokenRefresh();
  }

  void _scheduleTokenRefresh() {
    _tokenRefreshTimer?.cancel();

    if (_currentTokens == null) return;

    // Refresh 5 minutes before expiry
    final refreshTime = _currentTokens!.expiresAt
        .subtract(const Duration(minutes: 5))
        .difference(DateTime.now());

    if (refreshTime.isNegative) {
      // Token is already near expiry, refresh immediately
      _refreshTokens().catchError((_) => logout());
      return;
    }

    _tokenRefreshTimer = Timer(refreshTime, () {
      _refreshTokens().catchError((_) => logout());
    });
  }

  Future<void> _clearAllData() async {
    _tokenRefreshTimer?.cancel();
    _currentTokens = null;
    await Future.wait([
      _secureStorage.deleteTokens(),
      _sessionStorage.clearSession(),
    ]);
  }

  void _emitState(AuthState state) {
    _currentState = state;
    _authStateController.add(state);
  }

  /// Dispose resources
  void dispose() {
    _tokenRefreshTimer?.cancel();
    _authStateController.close();
  }
}

// lib/widgets/auth_builder.dart
import 'package:flutter/material.dart';

import '../auth/auth_manager.dart';
import '../auth/auth_state.dart';

class AuthBuilder extends StatelessWidget {
  final AuthManager authManager;
  final Widget Function(BuildContext context, UserModel user) authenticated;
  final Widget Function(BuildContext context) unauthenticated;
  final Widget Function(BuildContext context)? loading;
  final Widget Function(BuildContext context, String error)? error;

  const AuthBuilder({
    super.key,
    required this.authManager,
    required this.authenticated,
    required this.unauthenticated,
    this.loading,
    this.error,
  });

  @override
  Widget build(BuildContext context) {
    return StreamBuilder<AuthState>(
      stream: authManager.authStateChanges,
      initialData: authManager.currentState,
      builder: (context, snapshot) {
        final state = snapshot.data ?? const AuthState.unknown();

        switch (state.status) {
          case AuthStatus.authenticated:
            return authenticated(context, state.user!);
          case AuthStatus.unauthenticated:
            return unauthenticated(context);
          case AuthStatus.loading:
          case AuthStatus.unknown:
            return loading?.call(context) ??
                const Scaffold(
                  body: Center(child: CircularProgressIndicator()),
                );
          case AuthStatus.error:
            return error?.call(context, state.errorMessage ?? 'Unknown error') ??
                unauthenticated(context);
        }
      },
    );
  }
}

