                          fontWeight: FontWeight.w600,
                        ),
                      ),
                      const SizedBox(height: 4),
                      Text(
                        'Your session is active and persisted',
                        style: TextStyle(color: Colors.grey[600]),
                      ),
                    ],
                  ),
                ),
              ),
              const SizedBox(height: 24),
              OutlinedButton.icon(
                onPressed: () => _handleRefreshToken(context),
                icon: const Icon(Icons.refresh),
                label: const Text('Force Refresh Token'),
              ),
              const SizedBox(height: 12),
              FilledButton.icon(
                onPressed: () => _handleLogout(context),
                icon: const Icon(Icons.logout),
                label: const Text('Sign Out'),
                style: FilledButton.styleFrom(
                  backgroundColor: Colors.red,
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }

  Future<void> _handleLogout(BuildContext context) async {
    final confirmed = await showDialog<bool>(
      context: context,
      builder: (context) => AlertDialog(
        title: const Text('Sign Out'),
        content: const Text('Are you sure you want to sign out?'),
        actions: [
          TextButton(
            onPressed: () => Navigator.of(context).pop(false),
            child: const Text('Cancel'),
          ),
          FilledButton(
            onPressed: () => Navigator.of(context).pop(true),
            child: const Text('Sign Out'),
          ),
        ],
      ),
    );

    if (confirmed == true) {
      await authManager.logout();
    }
  }

  Future<void> _handleRefreshToken(BuildContext context) async {
    try {
      await authManager.forceRefreshToken();
      if (context.mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(
            content: Text('Token refreshed successfully'),
            backgroundColor: Colors.green,
          ),
        );
      }
    } catch (e) {
      if (context.mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: Text('Failed to refresh token: $e'),
            backgroundColor: Colors.red,
          ),
        );
      }
    }
  }
}

// lib/main.dart
import 'package:flutter/material.dart';

import 'auth/auth_manager.dart';
import 'auth/auth_state.dart';
import 'models/user_model.dart' as models;
import 'screens/home_screen.dart';
import 'screens/login_screen.dart';

void main() {
  WidgetsFlutterBinding.ensureInitialized();
  final authManager = AuthManager();
  runApp(MyApp(authManager: authManager));
}

class MyApp extends StatefulWidget {
  final AuthManager authManager;

  const MyApp({super.key, required this.authManager});

  @override
  State<MyApp> createState() => _MyAppState();
}

class _MyAppState extends State<MyApp> {
  @override
  void initState() {
    super.initState();
    widget.authManager.initialize();
  }

  @override
  void dispose() {
    widget.authManager.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Auth Manager Demo',
      debugShowCheckedModeBanner: false,
      theme: ThemeData(
        colorSchemeSeed: Colors.blue,
        useMaterial3: true,
        brightness: Brightness.light,
      ),
      darkTheme: ThemeData(
        colorSchemeSeed: Colors.blue,
        useMaterial3: true,
        brightness: Brightness.dark,
      ),
      home: StreamBuilder<AuthState>(
        stream: widget.authManager.authStateChanges,
        initialData: widget.authManager.currentState,
        builder: (context, snapshot) {
          final state = snapshot.data ?? const AuthState.unknown();

          switch (state.status) {
            case AuthStatus.authenticated:
              return HomeScreen(
                authManager: widget.authManager,
                user: state.user! as models.UserModel,
              );
            case AuthStatus.unauthenticated:
            case AuthStatus.error:
              return LoginScreen(authManager: widget.authManager);
            case AuthStatus.loading:
            case AuthStatus.unknown:
              return const Scaffold(
                body: Center(
                  child: Column(
                    mainAxisAlignment: MainAxisAlignment.center,
                    children: [
                      CircularProgressIndicator(),
                      SizedBox(height: 16),
                      Text('Restoring session...'),
                    ],
                  ),
                ),
              );
          }
        },
      ),
    );
  }
}